// Hand-maintained — NOT generated by `wrangler types`.
//
// `wrangler types` produces a ~548KB file that migrates away from
// @cloudflare/workers-types to a new runtime-types system, omits IP_SALT
// (secrets never appear in generated types), and introduces a CacheStorage
// typing conflict. For this worker's two bindings, hand-writing is simpler
// and more correct than reconciling that generated output.
//
// Bindings:
//   DB       - D1 database, declared in wrangler.jsonc (d1_databases).
//   IP_SALT  - secret, set via `wrangler secret put IP_SALT` (never in
//              wrangler.jsonc or generated types).
interface Env {
  DB: D1Database
  IP_SALT: string
}
